import type { HotjarStore } from './types';

import { getReq } from '@meli/server-context';

import { getConfigProps } from './utils';

export async function createHotjarStore(): Promise<HotjarStore> {
  const req = getReq();

  return {
    enabled: false,
    props: {},
    configProps: getConfigProps('hotjar'),
    debugMode: !!(req.header('x-hotjar-debug') || req.query.hotjar_debug),
    hasUserConsent:
      (await req.meliCookies?.userConsentCookieCategory('traceability')) ??
      false,
  };
}
